package com.google.gson;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.util.ArrayList;

public class JsonArrayTest {

  private JsonArray jsonArray;
  private ArrayList<JsonElement> mockElements;

  @BeforeEach
  public void setUp() throws Exception {
    jsonArray = new JsonArray();

    // Create a mock ArrayList<JsonElement>
    mockElements = mock(ArrayList.class);

    // Use reflection to set the private final field 'elements' to the mock
    Field elementsField = JsonArray.class.getDeclaredField("elements");
    elementsField.setAccessible(true);
    elementsField.set(jsonArray, mockElements);
  }

  @Test
  public void testHashCode_returnsElementsHashCode() {
    int expectedHashCode = 123456789;
    when(mockElements.hashCode()).thenReturn(expectedHashCode);

    int actualHashCode = jsonArray.hashCode();

    assertEquals(expectedHashCode, actualHashCode);
  }
}
